class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = Player('B')
        self.game_over = False
        self.turns_played = 0

    def switch_turn(self):
        if self.current_player.color == 'B':
            self.current_player = Player('W')
        else:
            self.current_player = Player('B')

    def get_valid_moves(self, board, piece):
        moves = []
        row, col = piece
        color = board.get_piece(row, col)

        # Check for regular moves and captures
        if color == 'B':
            moves.extend([(row + 1, col - 1), (row + 1, col + 1)])
            if (color == 'B' and row == 0) or (color == 'W' and row == 7):
                moves.extend([(row + 2, col - 2), (row + 2, col + 2)])
        elif color == 'W':
            moves.extend([(row - 1, col - 1), (row - 1, col + 1)])
            if (color == 'B' and row == 0) or (color == 'W' and row == 7):
                moves.extend([(row - 2, col - 2), (row - 2, col + 2)])

        # Filter out invalid moves
        valid_moves = []
        for move in moves:
            if board.get_piece(*move) == ' ':
                valid_moves.append(move)

        return valid_moves

    def make_move(self, from_pos, to_pos):
        row1, col1 = int(from_pos[0]), int(from_pos[1])
        row2, col2 = int(to_pos[0]), int(to_pos[1])

        piece = self.board.get_piece(row1, col1)
        if piece != self.current_player.color:
            print("Invalid move. It's not your turn or you're trying to move the wrong piece.")
            return

        valid_moves = self.get_valid_moves((row1, col1), (row2, col2))
        if (row2, col2) in valid_moves:
            self.board.set_piece(row2, col2, piece)
            self.board.set_piece(row1, col1, ' ')

            # Handle captures
            if abs(row2 - row1) == 2:
                captured_row = (row1 + row2) // 2
                captured_col = (col1 + col2) // 2
                self.board.set_piece(captured_row, captured_col, ' ')
        else:
            print("Invalid move. Please enter a valid move.")

    def check_winner(self):
        if not any('B' in row for row in self.board.board):
            print("Player W wins!")
            return True
        elif not any('W' in row for row in self.board.board):
            print("Player B wins!")
            return True
        else:
            return False

    def play_game(self):
        while not self.game_over:
            self.board.print_board()
            print(f"Player {self.current_player.color}'s turn")
            from_pos = input("Enter move (from-to): ")

            # Validate and make the move
            if len(from_pos) != 2 or not from_pos.isdigit():
                print("Invalid input. Please enter a valid position.")
                continue

            to_pos = input("Enter move (from-to): ")
            if len(to_pos) != 2 or not to_pos.isdigit():
                print("Invalid input. Please enter a valid position.")
                continue

            self.make_move(from_pos, to_pos)

            # Check for winner after each move
            if self.check_winner():
                break

            # Switch turns
            self.switch_turn()
